using namespace std;

#define MAXNAMESIZE 1024
#define SEED 1
#define SP 1
#define ITER 3
#define PROFILE
#define CACHE_LINE 512

typedef struct {
  float weight;
  float *coord;
  long assign;
  float cost;
} Point;

typedef struct {
  long num;
  int dim;
  Point *p;
} Points;

static bool *switch_membership;
static bool *is_center;
static int *center_table;
float *block;

static int nproc;
